pattern_before:
// Two slots always — one for metadata, one for value
sstore(metadataSlot, metadata)
sstore(valueSlot, value)

pattern_after:
// One slot for small values, two for large
if iszero(or(eq(value, address()), shr(160, value))) {
    sstore(slot, or(metadata, shl(96, value)))
} else {
    sstore(slot, or(metadata, shl(96, address()))) // sentinel
    sstore(not(slot), value) // overflow slot
}
